) -> Json<corvia_common::dashboard::GcStatusResponse> {
    let last_run = state.gc_history.last().map(gc_report_to_dto);
    let history: Vec<corvia_common::dashboard::GcReportDto> = state
        .gc_history
        .all()
        .into_iter()
        .map(gc_report_to_dto)
        .collect();

    Json(corvia_common::dashboard::GcStatusResponse {
        last_run,
        history,
        scheduled: false,
    })
}
